#include<cstdio>
const int N=3e5+10;int cf[N],l[N],r[N],qzh[2][N];
int main(void){
	int n,m;scanf("%d%d",&n,&m);
	for(int i=1;i<=m;++i)scanf("%d%d",&l[i],&r[i]),++cf[l[i]],--cf[r[i]+1];
	for(int i=1;i<=n;++i)cf[i]+=cf[i-1];
	for(int i=1;i<=n;++i)
		for(int j=0;j<2;++j)
			qzh[j][i]=qzh[j][i-1]+(cf[i]==j);
	for(int i=1;i<=m;++i)
		printf("%d\n",qzh[0][l[i]-1]+qzh[0][n]-qzh[0][r[i]]+qzh[1][r[i]]-qzh[1][l[i]-1]);
	return false;
}
